INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9f3f6c23-b787-4b71-840e-5d7aac5ecaf9',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS + Redis — Cache-Aside, Write-Through, and Eviction in Message-Driven Services$escape$,
  $escape$When NATS queue subscribers hit a database on every message, latency compounds fast. Redis slots naturally between your NATS handler and Postgres. Cache-aside is the default: on a cache miss, the handler fetches from DB, writes to Redis with TTL, and continues. TTL must be shorter than your NATS stream's MaxAge — stale cache entries that outlive message retention cause silent inconsistencies.

Write-through suits idempotent NATS handlers: write to Redis and DB atomically before ACKing the message. If the subscriber crashes post-write but pre-ACK, NATS redelivers; Redis deduplicates via the cached key.

Write-behind is riskier: the handler updates Redis immediately, ACKs, then publishes a secondary subject (`db.sync.*`) consumed by a durable JetStream consumer that flushes to Postgres asynchronously. You get lower p99 latency but accept a data-loss window if the sync consumer lags.

For eviction, prefer `allkeys-lru` in read-heavy NATS fan-out topologies. Use `volatile-ttl` when only TTL-tagged keys are cache-eligible. Avoid `noeviction` entirely — NATS redelivery storms under backpressure will OOM your Redis node fast.$escape$,
  $escape$// Cache-aside inside a NATS queue subscriber (Go)
nc, _ := nats.Connect(nats.DefaultURL)

nc.QueueSubscribe("user.fetch.*", "workers", func(msg *nats.Msg) {
    userID := strings.TrimPrefix(msg.Subject, "user.fetch.")
    cacheKey := "user:" + userID

    if cached, err := rdb.Get(ctx, cacheKey).Bytes(); err == nil {
        msg.Respond(cached)
        return
    }

    user := db.FindUser(userID)
    data, _ := json.Marshal(user)
    rdb.Set(ctx, cacheKey, data, 5*time.Minute)
    msg.Respond(data)
})$escape$,
  $escape$go$escape$,
