INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b3f6fe19-7a39-42cf-85f1-5fa6af7dd6bc',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream vs Core Pub/Sub — Picking the Right Queue Primitive$escape$,
  $escape$NATS gives you three distinct queuing models with different durability guarantees. Core pub/sub is fire-and-forget — messages vanish if no subscriber is connected. Zero persistence, at-most-once delivery. Useful for real-time telemetry where stale data is worthless, not for jobs.

JetStream Streams flip the model: messages persist to disk or memory and replay on demand. Consumers can be push-based (server delivers) or pull-based (worker polls), with configurable ack policies — AckExplicit, AckAll, or AckNone. This is your durable, ordered, replayable channel — analogous to Redis Streams.

For task queues specifically, use JetStream with WorkQueuePolicy retention: each message is delivered to exactly one consumer in the group, then deleted on ack. Unlike Core queue groups — which silently drop unacked messages on subscriber crash — JetStream redelivers after AckWait expires, up to MaxDeliver attempts, then routes to a dead-letter subject.

Persistence trade-off is explicit: FileStorage survives restarts, MemoryStorage is faster but volatile. For critical workloads, pair FileStorage with Replicas: 3 on a clustered NATS server to survive a node loss without data loss.$escape$,
  $escape$nc, _ := nats.Connect(nats.DefaultURL)
js, _ := nc.JetStream()

// Durable work-queue stream: one consumer gets each message, deleted on ack
js.AddStream(&nats.StreamConfig{
    Name:      "JOBS",
    Subjects:  []string{"jobs.*"},
    Retention: nats.WorkQueuePolicy,
    Storage:   nats.FileStorage,
    Replicas:  3,
})

// Pull consumer — workers compete; server tracks ack state
sub, _ := js.PullSubscribe("jobs.*", "worker-group")
msgs, _ := sub.Fetch(10, nats.MaxWait(5*time.Second))
for _, msg := range msgs {
    process(msg)
    msg.Ack() // deleted from stream only after explicit ack
}$escape$,
