INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7544eb6b-6ca8-4763-99d4-89116355e857',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream — BullMQ Patterns: Priorities, Rate Limits, Repeatable Jobs, and Dependency Chains$escape$,
  $escape$NATS JetStream has no BullMQ primitives, but you can replicate all four patterns natively. For job priorities, model them as separate subjects — `jobs.high`, `jobs.normal`, `jobs.low` — bound to a single stream. Spin up consumers that drain `jobs.high` first; subject-level filtering gives you the ordering without a priority queue abstraction.

Rate limiting maps directly to `MaxAckPending` on a push or pull consumer. Set it to your desired concurrency ceiling — JetStream will stop delivering new messages once that many are unacknowledged, giving you backpressure without a token bucket.

Repeatable jobs have no native scheduler in NATS, but a simple goroutine ticker that calls `js.Publish` on each interval is idiomatic and resilient — pair it with a KV store flag to make it single-leader across replicas.

Dependency chains work via ack-then-publish: after a worker calls `msg.Ack()`, it publishes the dependent job to the next subject. Because JetStream delivery is durable, the downstream job is guaranteed even if the producer crashes mid-flight — the dependent message is already persisted before the parent ack is sent.$escape$,
  $escape$js, _ := nc.JetStream()

js.AddStream(&nats.StreamConfig{
    Name:     "JOBS",
    Subjects: []string{"jobs.high", "jobs.normal", "jobs.low"},
})

// Rate-limit: max 5 concurrent jobs
js.AddConsumer("JOBS", &nats.ConsumerConfig{
    Durable:       "workers",
    FilterSubject: "jobs.high",
    MaxAckPending: 5,
    AckWait:       30 * time.Second,
})

// Repeatable job every minute
go func() {
    for range time.NewTicker(time.Minute).C {
        js.Publish("jobs.normal", payload)
    }
}()

// Dependency chain: ack then enqueue child
js.Subscribe("jobs.high", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack()
    js.Publish("jobs.low", childPayload) // persisted before ack returns
})$escape$,
  $escape$go$escape$,
