INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd7bd8f01-15fc-42a1-8faa-fb7f5da008e5',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream as a Celery Alternative — Routing, Results, and Chaining$escape$,
  $escape$Celery abstractions map cleanly onto NATS JetStream primitives — without a separate broker process. For task routing, model priority lanes as subject hierarchies: `tasks.high.*`, `tasks.low.*`. Bind queue-group consumers per lane so workers pull only their tier. For a result backend, skip Redis entirely — JetStream's Key-Value store gives you durable, TTL-scoped result storage with `js.create_key_value(bucket='task_results')`. Write the result under the message's Nats-Msg-Id; readers poll or watch the bucket. Task chaining works via reply subjects: the producer sets `reply_to='tasks.report'` on the initial publish, and the email worker republishes its output to that subject on completion — zero coordinator needed. For beat-style scheduling, NATS lacks a native cron trigger, so pair a lightweight APScheduler process that calls `js.publish()` on interval — the JetStream stream absorbs bursts and provides deduplication via `Nats-Msg-Id` headers, preventing double-execution on scheduler restart.$escape$,
  $escape$import asyncio, nats
from nats.js.api import StreamConfig, KeyValueConfig

async def main():
    nc = await nats.connect()
    js = nc.jetstream()

    await js.add_stream(StreamConfig(name="TASKS", subjects=["tasks.>"]))
    kv = await js.create_key_value(KeyValueConfig(bucket="task_results", ttl=3600))

    # Route high-priority task; chain output to tasks.report
    await js.publish("tasks.high.email", b'{"user":"alice"}',
                     headers={"Nats-Msg-Id": "t-001"},
                     stream="TASKS")

    # Worker writes result to KV (result backend)
    await kv.put("t-001", b'{"status":"sent"}')

    # Chained consumer reads tasks.report triggered by reply_to
    sub = await js.subscribe("tasks.report", queue="report-workers")
    msg = await sub.next_msg(timeout=5)
    await msg.ack()

asyncio.run(main())$escape$,
  $escape$python$escape$,
