INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fa5b50d4-e2ee-4a2d-b829-e0e5567f5e19',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream Backpressure — Keeping Lagging Consumers From Blowing Up Memory$escape$,
  $escape$NATS JetStream has two consumer modes, and backpressure behaves differently in each. With push consumers, a lagging subscriber causes the server to keep buffering undelivered messages on the client side — your process heap grows until you OOM. The fix is `MaxAckPending` on the consumer config: once in-flight unacked messages hit that ceiling, JetStream pauses delivery automatically until ACKs drain it back down.

Pull consumers are inherently backpressure-safe. `cons.Fetch(n)` is a demand-driven request — the server sends exactly `n` messages and stops. Your processing loop becomes the throttle; memory stays bounded by definition.

For push consumers under sustained lag, pair `MaxAckPending` with a tight `AckWait`. Without it, timed-out messages redeliver on top of new ones, compounding pressure. `MaxDeliver` caps retry storms from poison messages.

For production workloads, pull consumers with a fixed `Fetch` window are the idiomatic NATS pattern. You get bounded memory, natural flow control, and real-time consumer health via `cons.Info()` — `NumPending` and `NumAckPending` tell you exactly where lag is building before it becomes a crisis.$escape$,
  $escape$cons, _ := js.CreateOrUpdateConsumer(ctx, "ORDERS", jetstream.ConsumerConfig{
    Durable:       "processor",
    MaxAckPending: 50,
    AckWait:       20 * time.Second,
    MaxDeliver:    5,
})

for {
    msgs, _ := cons.Fetch(10, jetstream.FetchMaxWait(5*time.Second))
    for msg := range msgs.Messages() {
        if err := process(msg); err != nil {
            msg.Nak()
            continue
        }
        msg.Ack()
    }
}$escape$,
  $escape$go$escape$,
