INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '814e58dc-c1e8-4a47-8ca5-950eae00deb0',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream Ordering — Subject-Based Partitioning for Guaranteed Sequence$escape$,
  $escape$NATS JetStream doesn't expose numeric partitions like Kafka — ordering is per-subject. To process events in order, publish to a subject hierarchy keyed on a stable partition token, then bind one ordered consumer per partition.

Partition by hashing the entity key (user ID, order ID) modulo N and publishing to `events.p{n}`. JetStream's ordered consumer delivers messages in stream sequence within its `FilterSubjects`, with `MaxDeliver: 1` enforced automatically — no gaps, no duplicates.

Spin up N goroutines, each owning one partition's `OrderedConsumer`. Since ordered consumers are ephemeral and stateless, restarts are safe — JetStream resumes from the last delivered sequence without explicit ack state management.

Avoid multiplexing one consumer across partitions: a slow message on `events.p2` won't stall `events.p3`. Cross-partition ordering is intentionally undefined. If global ordering is required, collapse to a single subject — but accept that throughput is now single-threaded. Subject design is your partition contract; get it right at schema time, not after data accumulates.$escape$,
  $escape$js, _ := jetstream.New(nc)

js.CreateStream(ctx, jetstream.StreamConfig{
    Name:     "EVENTS",
    Subjects: []string{"events.>"},
})

// Publisher: hash entity key into partition subject
subject := fmt.Sprintf("events.p%d", userID%8)
js.Publish(ctx, subject, payload)

// Consumer: pin to one partition for ordered delivery
cons, _ := js.OrderedConsumer(ctx, "EVENTS", jetstream.OrderedConsumerConfig{
    FilterSubjects: []string{"events.p3"},
})
iter, _ := cons.Messages()
for {
    msg, _ := iter.Next()
    process(msg)
    msg.Ack()
}$escape$,
  $escape$go$escape$,
