INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3031c52c-2860-4eb8-aee7-9ff431322069',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream — Queue Depth, Consumer Lag, and Dead Letter Alerts$escape$,
  $escape$JetStream exposes consumer health directly via `js.ConsumerInfo("stream", "consumer")`. The returned `*nats.ConsumerInfo` carries two critical lag fields: `NumPending` (messages in the stream not yet delivered to this consumer) and `NumAckPending` (delivered but unacknowledged — in-flight). Poll these on a ticker and alert when either breaches a threshold.

For dead-letter alerting, NATS publishes advisory events to `$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.<stream>.<consumer>` whenever a message exceeds its `MaxDeliver` limit. Each advisory payload carries the stream sequence number of the poisoned message. Subscribe to this subject and route those sequences to a dedicated `DEAD_LETTER` stream via `js.Publish` in the handler.

The `/jsz?consumers=true` HTTP monitoring endpoint exposes the same fields in JSON, making it trivial to scrape with Prometheus without touching the Go client. Use both approaches together: consumer polling catches throughput degradation early; advisory subscriptions fire the moment a message is poisoned. One tells you the system is slow — the other tells you it's broken.$escape$,
  $escape$js, _ := nc.JetStream()

info, _ := js.ConsumerInfo("ORDERS", "processor")
if info.NumPending > 1000 {
    log.Printf("ALERT: queue depth %d exceeds threshold", info.NumPending)
}
if info.NumAckPending > 100 {
    log.Printf("ALERT: consumer lag — %d unacked messages", info.NumAckPending)
}

// Dead letter: fires when MaxDeliver is exceeded
nc.Subscribe("$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.ORDERS.processor",
    func(msg *nats.Msg) {
        log.Printf("ALERT: dead letter advisory — seq poisoned: %s", msg.Data)
        js.Publish("DEAD_LETTER", msg.Data)
    },
)$escape$,
  $escape$go$escape$,
